const body = $json.body ?? $json;

function firstItem(x) {
  if (!x) return null;
  if (Array.isArray(x)) return x[0] ?? null;
  if (x.event && typeof x.event === "object") return x.event;
  if (typeof x === "object") {
    const keys = Object.keys(x);
    const numericKeys = keys.filter(k => /^\\d+$/.test(k)).sort((a,b) => Number(a)-Number(b));
    if (numericKeys.length) return x[numericKeys[0]];
  }
  return x;
}

const event = firstItem(body);
if (!event) return [{ json: { skip: true, reason: "no_event" } }];

// Ignore bot messages
if (event.bot_id || event.subtype === "bot_message") {
  return [{ json: { skip: true, reason: "bot_message" } }];
}

if (event.type !== "message") {
  return [{ json: { skip: true, reason: "not_message" } }];
}

// === ROUTING CONFIG ===
// Add your marketing channel ID here (right-click channel > View details > scroll to bottom)
const MARKETING_CHANNEL = "C0AAULKU604"; // UPDATE THIS with your actual channel ID

const isDm = event.channel_type === "im" || (typeof event.channel === "string" && event.channel.startsWith("D"));
const isMarketingChannel = event.channel === MARKETING_CHANNEL;

// Determine agent and conversation context
let agent, conversationPrefix;
if (isMarketingChannel) {
  agent = "marketing";
  conversationPrefix = "slack:marketing";
} else if (isDm) {
  agent = "product-manager";
  conversationPrefix = "slack:pm";
} else {
  // Not a DM and not the marketing channel - skip
  return [{ json: { skip: true, reason: "not_monitored_channel", channel: event.channel } }];
}

const text = (event.text || "").trim();
if (!text) {
  return [{ json: { skip: true, reason: "empty_text" } }];
}

return [{
  json: {
    skip: false,
    agent,
    conversationId: `${conversationPrefix}:${event.channel}`,
    slack: {
      channel: event.channel,
      threadTs: event.thread_ts || event.ts,
      user: event.user,
      text
    }
  }
}];

const job = {
  agent: $json.agent,
  message: $json.slack.text,
  conversationId: $json.conversationId,
  workingDir: "{{DEFAULT_WORKING_DIR}}",
  callbackUrl: "{{N8N_PUBLIC_URL}}/webhook/runner/callback",
  slack: {
    channel: $json.slack.channel,
    threadTs: $json.slack.threadTs,
    user: $json.slack.user
  }
};

return [{ json: { job } }];

const runner = $node["Call runner"].json || {};
const slack = $node["Build runner job"].json.job.slack;

const text =
  runner.result ||
  runner.output ||
  runner.message ||
  (typeof runner === "string" ? runner : JSON.stringify(runner, null, 2));

return [{
  json: {
    channel: slack.channel,
    threadTs: slack.threadTs,
    text
  }
}];
